from itertools import combinations, product
def subsets(n,k): return [tuple(c) for c in combinations(range(n),k)]
def key(s): return tuple(sorted(s))
def is_val_matroid_uniform(vals,n,r):
    # vals dict for all r-subsets finite 0/1
    if r<2 or r>n-2:
        return True
    for S in combinations(range(n), r-2):
        S=set(S)
        rest=[i for i in range(n) if i not in S]
        for quad in combinations(rest,4):
            i,j,k,l=quad
            terms=[
                vals[key(S|{i,j})]+vals[key(S|{k,l})],
                vals[key(S|{i,k})]+vals[key(S|{j,l})],
                vals[key(S|{i,l})]+vals[key(S|{j,k})],
            ]
            m=min(terms)
            if terms.count(m)<2:
                return False
    return True

def incidence_nested(p,q,n,a,b):
    for S in subsets(n,a-1):
        Sset=set(S)
        # T size b+1 containing S
        for T in subsets(n,b+1):
            Tset=set(T)
            if not Sset <= Tset: continue
            terms=[]
            for i in Tset-Sset:
                terms.append(p[key(Sset|{i})]+q[key(Tset-{i})])
            m=min(terms)
            if terms.count(m)<2:
                return False
    return True

def incidence_full(p,q,n,a,b):
    for I in subsets(n,a-1):
        Iset=set(I)
        for J in subsets(n,b+1):
            Jset=set(J)
            terms=[]
            for i in Jset-Iset:
                terms.append(p[key(Iset|{i})]+q[key(Jset-{i})])
            if len(terms)==0: continue
            m=min(terms)
            if terms.count(m)<2:
                return False, (I,J,terms)
    return True, None

