from itertools import combinations, product
def adj_inc(vals_d, vals_e, n, d):
    # ranks d and d+1, nested three-term: S size d-1, distinct x,y,z outside S
    if d==0:
        return True # no S size -1
    if n-(d-1)<3:
        return True
    for S in combinations(range(n), d-1):
        Sset=set(S)
        rest=[x for x in range(n) if x not in Sset]
        for xyz in combinations(rest,3):
            terms=[]
            for idx,e in enumerate(xyz):
                pair=set(xyz)-{e}
                terms.append(vals_d[key(Sset|{e})]+vals_e[key(Sset|pair)])
            m=min(terms)
            if terms.count(m)<2:
                return False
    return True

